import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import TestimonialCard from "./TestimonialCard";

// Lista de testimonios
const testimonials = [
  {
    name: "Anonymous",
    text: "I am constantly running with 3 kids &...",
    rating: 5,
    bgColor: "#D9F3EC",
  },
  {
    name: "Kristi",
    text: "I started to replace my afternoon cup of coffee...",
    rating: 5,
    bgColor: "#C2DFE3",
  },
  {
    name: "Anonymous",
    text: "I hate water but since finding Hydrant...",
    rating: 5,
    bgColor: "#FAE7DC",
  },
  {
    name: "User4",
    text: "Great product!",
    rating: 5,
    bgColor: "#DCE3F3",
  },
  {
    name: "User5",
    text: "Super refreshing.",
    rating: 5,
    bgColor: "#FFE2DA",
  },
  {
    name: "User6",
    text: "Helps me focus all day.",
    rating: 5,
    bgColor: "#EDDCA9",
  },
  {
    name: "User7",
    text: "My skin looks hydrated and radiant.",
    rating: 5,
    bgColor: "#CCFFCC",
  },
];

// Animación con dirección
const variants = {
  enter: (direction) => ({
    x: direction > 0 ? 300 : -300,
    opacity: 0,
  }),
  center: {
    x: 0,
    opacity: 1,
  },
  exit: (direction) => ({
    x: direction < 0 ? 300 : -300,
    opacity: 0,
  }),
};

function PersonalSection() {
  const [[page, direction], setPage] = useState([0, 0]);

  const paginate = (newDirection) => {
    const newPage = (page + newDirection + testimonials.length) % testimonials.length;
    setPage([newPage, newDirection]);
  };

  const testimonial = testimonials[page];

  return (
    <section
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        padding: "3rem 1rem",
      }}
    >
      <h2
        style={{
          fontWeight: "900",
          fontSize: "2.5rem",
          textAlign: "center",
          marginBottom: "2rem",
        }}
      >
        LOVED BY THOUSANDS
      </h2>

      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "1rem",
        }}
      >
        {/* Botón Izquierda */}
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={() => paginate(-1)}
          style={arrowButton}
        >
          ◀
        </motion.button>

        {/* Testimonio actual */}
        <div style={{ width: 300, minHeight: 350, position: "relative" }}>
          <AnimatePresence custom={direction} mode="popLayout">
            <motion.div
              key={page}
              custom={direction}
              variants={variants}
              initial="enter"
              animate="center"
              exit="exit"
              transition={{ type: "spring", stiffness: 300, damping: 30 }}
              style={{
                position: "absolute",
                width: "100%",
              }}
            >
              <TestimonialCard {...testimonial} />
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Botón Derecha */}
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={() => paginate(1)}
          style={arrowButton}
        >
          ▶
        </motion.button>
      </div>
    </section>
  );
}

const arrowButton = {
  width: 40,
  height: 40,
  borderRadius: "50%",
  fontSize: "1.5rem",
  border: "none",
  backgroundColor: "#003E73",
  color: "white",
  cursor: "pointer",
};

export default PersonalSection;
